import"./main-pwrAVdOD.js";import"./administration-CNzdiowZ.js";const s=`{% block sw_sso_error %} <div class="sw-sso-error"> <div class="sw-sso-error__container"> <div class="sw-sso-error__image-container"> <img width="200" :src="assetFilter('administration/administration/static/img/shopware_logo_blue.svg')" :alt="$t('global.sw-sso-error.error-card.logoAltText')" > </div> <mt-card position-identifier="sw-sso-error-card" class="sw-sso-error-card" > <div class="lock-icon"> <mt-icon class="block" name="solid-lock" size="24px" /> </div> <h1 class="sw-sso-error__title"> {{ $t('global.sw-sso-error.error-card.title') }} </h1> <p class="sw-sso-error__description"> {{ $t('global.sw-sso-error.error-card.text') }} </p> <div class="sw-sso-error-card__button-container"> <div v-if="isLoading" class="sw-sso-error__loading-indicator" > <mt-loader /> </div> <a v-else :href="url" class="sw-button sw-button--primary" > {{ $t('global.sw-sso-error.error-card.button') }} </a> </div> <span class="sw-sso-error-card__small-text">{{ $t('global.sw-sso-error.error-card.loggedInAsPrefix') }}</span> <span v-if="email" class="sw-sso-error-card__small-text-email" > {{ email }} </span> </mt-card> </div> </div> {% endblock %}`,i={template:s,inject:["loginService"],data(){return{loginConfig:{},loginConfigLoaded:!1}},created(){this.loginService.getLoginTemplateConfig().then(r=>{this.loginConfig=r,this.loginConfigLoaded=!0})},computed:{assetFilter(){return Shopware.Filter.getByName("asset")},isLoading(){return!this.loginConfigLoaded},url(){return this.loginConfigLoaded?`${this.loginConfig.url}&usePromptLogin=1`:""},email(){return this.loginService.getStorage().getItem("user")}}};export{i as default};
